const entity = msg.topic;
const state = msg.payload;

let cycle = flow.get("outside_pending_cycle") || null;

function nowIso() {
    return new Date().toISOString();
}

// ─────────────────────────────────────────────
// Normalize HA outside control mode
//
// Purpose:
// - Converts current and legacy Home Assistant control mode names
//   into the short mode values stored in maintenance_log.
// - Keeps DB history consistent after the 2026-07-06 mode rename.
// ─────────────────────────────────────────────
function normalizeMode(controlMode) {
    const mode = String(controlMode || "").trim();

    if (mode === "Auto Fill - Auto Dose" || mode === "Auto") {
        return "auto";
    }

    if (mode === "Manual Fill - Auto Dose" || mode === "Manual") {
        return "manual";
    }

    if (mode === "ESP-Override") {
        return "esp-override";
    }

    return "unknown";
}

function titleForCycle(mode, eventType) {

    if (eventType === "FILL") {
        if (mode === "auto")
            return "🤖 Auto Fill - Auto Dose Complete";

        if (mode === "manual")
            return "🧪 Manual Fill - Auto Dose Complete";

        if (mode === "esp-override")
            return "🟥 ESP-Override Fill Complete";
    }

    // DOSE events
    if (mode === "esp-override")
        return "🟥 ESP-Override Dose Complete";

    if (mode === "auto")
        return "🤖 Auto Maintenance Dose Complete";

    return "🧪 Hydroponics Cycle Complete";
}

function newCycle(eventType) {
    const mode = normalizeMode(msg.control_mode);

    return {
        started_at: nowIso(),

        // Must come from HA control mode, not hardcoded.
        mode: mode,

        // GAL 2026-07-10 ISSUE-006:
        // Auto and Manual cycles wait for post-mixing TDS.
        // ESP-Override actions are intended for immediate logging.
        delay_tds_capture: mode !== "esp-override",

        source: "outside",
        location: "patio",
        device: "node_red_cycle_manager",
        event_type: eventType,

        system_gallons: null,
        gallons_added: null,

        dose_a_ml: null,
        dose_b_ml: null,

        tds_before: null,
        tds_after: null,

        fill_used: false,
        pump_a_used: false,
        pump_b_used: false
    };
}

// -----------------------------
// ACTION STARTED
// -----------------------------
if (state === "on") {

    flow.set("outside_cycle_active", true);

    if (entity.includes("water_fill_solenoid")) {
        // Fill starts a fill cycle.
        cycle = newCycle("FILL");
        cycle.fill_used = true;
        msg.capture_before = true;
        node.warn("NEW FILL CYCLE STARTED");
    }

    else if (entity.includes("nutrient_pump_a")) {
        if (!cycle) {
            // Dose-only cycle.
            cycle = newCycle("DOSE");
            msg.capture_before = true;
            node.warn("NEW DOSE CYCLE STARTED");
        } else {
            // Pump A is joining an existing fill cycle.
            node.warn("PUMP A JOINED ACTIVE CYCLE");
        }

        cycle.pump_a_used = true;
    }

    else if (entity.includes("nutrient_pump_b")) {
        if (!cycle) {
            cycle = newCycle("DOSE");
            msg.capture_before = true;
            node.warn("NEW DOSE CYCLE STARTED FROM PUMP B");
        } else {
            node.warn("PUMP B JOINED ACTIVE CYCLE");
        }

        cycle.pump_b_used = true;
    }

    // If water was used, final event is FILL even if dosing also happened.
    if (cycle.fill_used) {
        cycle.event_type = "FILL";
    }

    flow.set("outside_pending_cycle", cycle);
    msg.payload = cycle;
    return msg;
}

// -----------------------------
// ACTION STOPPED
// -----------------------------
if (state === "off") {

    if (!cycle) {
        node.warn("OFF event with no active cycle");
        return null;
    }

    cycle.last_activity = nowIso();

    // GAL 2026-07-10 ISSUE-006:
    // ESP-Override actions are independent events and must be logged
    // immediately after their actual quantity is captured.
    // Auto and Manual cycles continue through the delayed TDS path.
    msg.immediate_log = cycle.delay_tds_capture === false;

    // Finalize every ESP-Override action immediately.
    // Auto and Manual cycles finalize when Pump B completes.
    msg.finalize_cycle =
        msg.immediate_log ||
        entity.includes("nutrient_pump_b");

    if (entity.includes("water_fill_solenoid")) {
        msg.capture_fill_done = true;
        node.warn("Fill completed");
    }

    if (entity.includes("nutrient_pump_a")) {
        msg.capture_dose_a_done = true;
        node.warn("Pump A completed");
    }

    if (entity.includes("nutrient_pump_b")) {
        msg.capture_dose_b_done = true;
        node.warn("Pump B completed");
    }

    if (cycle.fill_used) {
        cycle.event_type = "FILL";
    }

    flow.set("outside_pending_cycle", cycle);
    msg.payload = cycle;
    return msg;
}

return null;

let cycle = flow.get("outside_pending_cycle") || {};

cycle.system_gallons = msg.event?.system_gallons ?? null;
cycle.tds_before = msg.event?.tds_before ?? null;

flow.set("outside_pending_cycle", cycle);

msg.payload = cycle;
return msg;
return msg;

let cycle = flow.get("outside_pending_cycle") || {};
cycle.gallons_added = msg.event?.gallons_added ?? null;
flow.set("outside_pending_cycle", cycle);
msg.payload = cycle;
return msg;
return msg;

let cycle = flow.get("outside_pending_cycle") || {};
cycle.dose_a_ml = msg.event?.dose_a_ml ?? null;
flow.set("outside_pending_cycle", cycle);
msg.payload = cycle;
return msg;
return msg;

let cycle = flow.get("outside_pending_cycle") || {};
cycle.dose_b_ml = msg.event?.dose_b_ml ?? null;
flow.set("outside_pending_cycle", cycle);
msg.payload = cycle;
return msg;
return msg;

// ─────────────────────────────────────────────────────────────
// Save TDS After
//
// GAL 2026-07-10 ISSUE-006
//
// Purpose:
// - Adds the post-mixing TDS value to the completed cycle snapshot.
// - Uses msg.completed_cycle instead of the shared flow context so
//   a newer maintenance dose can run while this cycle waits.
// ─────────────────────────────────────────────────────────────

const cycle = msg.completed_cycle;

if (!cycle) {
    node.warn("Missing completed_cycle in Save TDS After.");
    return null;
}

cycle.tds_after = msg.event?.tds_after ?? null;

msg.completed_cycle = cycle;
msg.payload = cycle;

return msg;

// ─────────────────────────────────────────────────────────────
// Build Cycle INSERT SQL
//
// GAL 2026-07-10 ISSUE-006
//
// Purpose:
// - Builds the MariaDB INSERT statement for one completed
//   hydroponics fill or maintenance dose cycle.
// - Uses the completed cycle snapshot carried in msg.completed_cycle
//   instead of the shared flow context.
// - Prevents overlapping maintenance cycles from overwriting
//   each other while waiting for post-mixing TDS stabilization.
// ─────────────────────────────────────────────────────────────

const e = msg.completed_cycle || {};

function txt(v) {
    if (v === undefined || v === null || v === "") return "NULL";
    return "'" + String(v).replace(/'/g, "''") + "'";
}

// Converts valid numeric values for SQL.
// Missing or unused values remain SQL NULL rather than becoming zero.
function num(v) {
    if (v === undefined || v === null || v === "") {
        return "NULL";
    }

    const n = Number(v);
    return Number.isFinite(n) ? String(n) : "NULL";
}

function fmtNum(v, decimals) {
    const n = Number(v);
    return Number.isFinite(n) ? n.toFixed(decimals) : null;
}

const mode = e.mode || "unknown";
const eventType = e.fill_used ? "FILL" : "DOSE";

let parts = [];
parts.push(mode);
parts.push(eventType);

let details = [];

if (Number(e.gallons_added) > 0) {
    details.push(`added ${fmtNum(e.gallons_added, 2)} gal water`);
}

if (Number(e.dose_a_ml) > 0) {
    details.push(`dose A ${fmtNum(e.dose_a_ml, 0)} mL`);
}

if (Number(e.dose_b_ml) > 0) {
    details.push(`dose B ${fmtNum(e.dose_b_ml, 0)} mL`);
}

if (Number.isFinite(Number(e.system_gallons))) {
    details.push(`system ${fmtNum(e.system_gallons, 1)} gal`);
}

if (Number.isFinite(Number(e.tds_before)) && Number.isFinite(Number(e.tds_after))) {
    details.push(`TDS ${fmtNum(e.tds_before, 3)} → ${fmtNum(e.tds_after, 3)} V`);
} else if (Number.isFinite(Number(e.tds_before))) {
    details.push(`TDS before ${fmtNum(e.tds_before, 3)} V`);
} else if (Number.isFinite(Number(e.tds_after))) {
    details.push(`TDS after ${fmtNum(e.tds_after, 3)} V`);
}

const note = `${parts.join(" ")}: ${details.join("; ")}`;

const raw = {
    ...e,
    final_mode: mode,
    final_event_type: eventType
};

msg.topic = `
INSERT INTO maintenance_log
(
  timestamp_utc,
  internal_time,
  source,
  location,
  device,
  event_type,
  mode,
  system_gallons,
  gallons_added,
  dose_a_ml,
  dose_b_ml,
  tds_before,
  tds_after,
  note,
  raw_message
)
VALUES
(
  UTC_TIMESTAMP(),
  NOW(),
  ${txt(e.source)},
  ${txt(e.location)},
  ${txt(e.device)},
  ${txt(eventType)},
  ${txt(mode)},
  ${num(e.system_gallons)},
  ${num(e.gallons_added)},
  ${num(e.dose_a_ml)},
  ${num(e.dose_b_ml)},
  ${num(e.tds_before)},
  ${num(e.tds_after)},
  ${txt(note)},
  ${txt(JSON.stringify(raw))}
);
`;

msg.payload = msg.topic;
return msg;

// ─────────────────────────────────────────────────────────────
// Clear Pending Cycle
//
// GAL 2026-07-10 ISSUE-006
//
// Purpose:
// - Marks the completed snapshot as fully logged and notified.
// - Does not clear flow.outside_pending_cycle here because that
//   shared slot was already released before the mixing timer.
// - Prevents this delayed completion path from clearing a newer
//   maintenance cycle that may already be active.
// ─────────────────────────────────────────────────────────────

msg.payload = "cycle logged and notified";
return msg;

// Build cycle completion notification.
//
// Uses the pending cycle captured by the Cycle Manager to generate the
// user-facing notification text for completed hydroponics control cycles.
//
// FILL cycles report:
//   • Water Added
//   • Starting Volume
//   • Calculated Final Volume
//
// DOSE cycles report:
//   • System Volume
//
// Detailed node purpose and revision history are maintained in the
// Node-RED Documentation tab.

const e = msg.completed_cycle || {};

function fmt(v, d = 2) {
    const n = Number(v);
    return Number.isFinite(n) ? n.toFixed(d) : "n/a";
}

function hasNumber(v) {
    return v !== undefined &&
        v !== null &&
        v !== "" &&
        Number.isFinite(Number(v));
}

function titleForCycle(mode, eventType) {

    if (eventType === "FILL") {
        if (mode === "auto")
            return "🤖 Auto Fill - Auto Dose Complete";

        if (mode === "manual")
            return "🧪 Manual Fill - Auto Dose Complete";

        if (mode === "esp-override")
            return "🟥 ESP-Override Fill Complete";
    }

    if (eventType === "DOSE") {
        if (mode === "auto")
            return "🤖 Auto Maintenance Dose Complete";

        if (mode === "esp-override")
            return "🟥 ESP-Override Dose Complete";
    }

    return "🧪 Hydroponics Cycle Complete";
}

const mode = e.mode || "unknown";
const eventType = e.fill_used ? "FILL" : "DOSE";

let lines = [];

msg.title = titleForCycle(mode, eventType);

if (eventType === "FILL") {
    if (mode === "esp-override") {
        lines.push("ESP-Override FILL completed");
    } else if (mode === "manual") {
        lines.push("Manual Fill - Auto Dose cycle completed");
    } else {
        lines.push("Auto Fill - Auto Dose cycle completed");
    }
}

if (e.gallons_added > 0) {
    lines.push(`Water Added: ${fmt(e.gallons_added)} gal`);
}

if (e.dose_a_ml > 0) {
    lines.push(`Dose A: ${fmt(e.dose_a_ml, 0)} mL`);
}

if (e.dose_b_ml > 0) {
    lines.push(`Dose B: ${fmt(e.dose_b_ml, 0)} mL`);
}

if (eventType === "FILL") {
    lines.push(`Starting Volume: ${fmt(e.system_gallons, 1)} gal`);

    const calculatedFinal = Number(e.system_gallons) + Number(e.gallons_added);
    if (Number.isFinite(calculatedFinal)) {
        lines.push(`Calculated Final Volume: ${fmt(calculatedFinal, 1)} gal`);
    }
} else {
    lines.push(`System Volume: ${fmt(e.system_gallons, 1)} gal`);
}

if (hasNumber(e.tds_before) && hasNumber(e.tds_after)) {
    lines.push(`TDS: ${fmt(e.tds_before, 3)} → ${fmt(e.tds_after, 3)}`);
} else if (hasNumber(e.tds_before)) {
    lines.push(`TDS Before: ${fmt(e.tds_before, 3)}`);
} else if (hasNumber(e.tds_after)) {
    lines.push(`TDS After: ${fmt(e.tds_after, 3)}`);
}

msg.payload = lines.join("\n");
return msg;

// ─────────────────────────────────────────────────────────────
// Snapshot Completed Cycle
//
// GAL 2026-07-10 ISSUE-006
//
// Purpose:
// - Copies one completed physical fill or dose event into the message.
// - Immediately releases the shared active-cycle slot.
// - Allows the next hardware event to start as a separate DB record.
// - Automatic cycles may continue through the post-mixing TDS path.
// - ESP-Override events may proceed directly to database logging.
// ─────────────────────────────────────────────────────────────

const cycle = flow.get("outside_pending_cycle");

if (!cycle) {
    node.warn("Cannot snapshot completed cycle: no pending cycle.");
    return null;
}

// Preserve this completed cycle independently of flow context.
msg.completed_cycle = JSON.parse(JSON.stringify(cycle));

// Release the shared cycle immediately.
flow.set("outside_pending_cycle", null);
flow.set("outside_cycle_active", false);

// Give each completed cycle an independent mixing timer.
msg.topic = msg.completed_cycle.started_at;

return msg;
